script:
// Optional hook object you can define:
// hooks = { onFrame(api, config, state){...}, draw(api, config, state, ctx){...} }
// For safety and simplicity, the core UI still renders; hooks can add extra lines.
hooks = {
  onFrame(api, config, state){
    // state.custom = ...
  }
};

hooks.draw:
(function(){
  try{
    // subtle dither/scanline overlay
    ctx.save();
    ctx.globalCompositeOperation='overlay';
    ctx.globalAlpha = 0.08;
    ctx.fillStyle = 'rgba(255,255,255,1)';
    for(let y=0;y<H;y+=3){ ctx.fillRect(0,y,W,1); }
    ctx.restore();

    // mini vignette
    ctx.save();
    ctx.globalCompositeOperation='multiply';
    const g = ctx.createRadialGradient(W*0.5,H*0.5, Math.min(W,H)*0.25, W*0.5,H*0.5, Math.min(W,H)*0.62);
    g.addColorStop(0,'rgba(255,255,255,1)');
    g.addColorStop(1,'rgba(0,0,0,0.55)');
    ctx.fillStyle=g;
    ctx.fillRect(0,0,W,H);
    ctx.restore();

    // watermark
    ctx.save();
    ctx.globalAlpha = 0.90;
    ctx.fillStyle = 'rgba(120,255,255,0.9)';
    ctx.font = (12*devicePixelRatio)+'px ui-monospace, Menlo, Consolas, monospace';
    ctx.fillText('MINIGORE MAP SHADER • ACTIVE (V2)', 16*devicePixelRatio, 86*devicePixelRatio);
    ctx.restore();
  }catch(e){}
})();
